    const longitude = bathroomDetail.longitude;
    const appleMapsUrl = `http://maps.apple.com/?ll=${latitude},${longitude}&q=${encodedLabel}`;
    const googleNavigationUrl = `google.navigation:q=${latitude},${longitude}`;
