      .select('*')
      .eq('id', bathroomId)
      .maybeSingle();

    if (error) {
      return {
        data: null,
        error: toAppError(error, 'Unable to load bathroom details.'),
      };
    }

    if (!data) {
      return {
        data: null,
        error: toAppError({ code: 'PGRST116', message: 'That bathroom could not be found.' }, 'That bathroom could not be found.'),
      };
    }

    return {
      data,
      error: null,
    };
  } catch (error) {
