  const value: AuthContextType = {
    sessionState,
    session,
    user,
    profile,
    authIssue,
    loading,
    signIn,
    signUp,
    signOut,
    refreshProfile,
    refreshUser,
    requireAuth,
    peekReturnIntent,
    consumeReturnIntent,
    clearReturnIntent,
    isGuest,
    isAuthenticated,
    canAccessProtectedRoute,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
