            ].join(' ')}
            disabled={isFavoritePending}
            onPress={(event: GestureResponderEvent) => {
              event.stopPropagation();
              onToggleFavorite();
            }}
          >
            <Ionicons
              color={isFavorited ? colors.brand[600] : colors.ink[500]}
