    (input: ToastInput): string => {
      const toast = buildToast(input);

      setToasts((currentToasts) => [...currentToasts.slice(-2), toast]);

      timers.current[toast.id] = setTimeout(() => {
        hideToast(toast.id);
      }, toast.duration);

      return toast.id;
