function formatAddress(detail: PublicBathroomDetailRow): string {
  return [
    detail.address_line1,
    [detail.city, detail.state].filter(Boolean).join(', '),
    detail.postal_code,
    detail.country_code,
  ]
    .filter(Boolean)
    .join(' ');
